import React, {useMemo, useCallback, type ElementType, type ReactElement} from 'react';
import {
    ActivityIndicator,
    Text as RNText,
    type TextStyle,
    type GestureResponderEvent,
} from 'react-native';
import type {IButtonProps, IconName} from '@lmb-it/kitsconcerto-types';
import {ResponsiveElement, useSeparator, style as resolveStyle} from '@lmb-it/kitsconcertomobile';
import {IconMap} from '../../assets/Icons';
import {useLanguage, useComponentDefaults} from '../../hooks';
import {useSeverityColors} from '../../hooks/useSeverityColors';

/* ─── Size configuration (matches web) ────────────────────────── */
const SIZE_MAP = {
    sm: {height: 32, fontSize: 12, px: 10, py: 6, gap: 6, iconSize: 14},
    md: {height: 40, fontSize: 14, px: 16, py: 10, gap: 8, iconSize: 16},
    lg: {height: 48, fontSize: 16, px: 24, py: 12, gap: 10, iconSize: 18},
} as const;

/* ─── Icon resolver ──────────────────────────────────────────── */
function resolveIcon(
    icon: unknown,
    color: string,
    iconSize: number,
): React.ReactNode {
    if (!icon) return null;
    if (React.isValidElement(icon)) {
        return React.cloneElement(icon as ReactElement<any>, {color, size: iconSize});
    }
    if (typeof icon === 'function') {
        const Comp = icon as ElementType;
        return <Comp size={iconSize} color={color} />;
    }
    if (typeof icon !== 'string') return null;
    const piMatches = icon.match(/pi-([a-z-]+)/g);
    const iconName = piMatches
        ? (piMatches[piMatches.length - 1]!.replace('pi-', '') as IconName)
        : (icon as IconName);
    const Component = IconMap[iconName];
    if (Component) return <Component size={iconSize} color={color} />;
    return null;
}

/* ─── Button Component ───────────────────────────────────────── */
export function Button(rawProps: IButtonProps<IconName | string | ElementType | ReactElement>) {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Button', rawProps);
    const {
        children,
        label,
        isLoadingText,
        severity = 'brand',
        size = 'md',
        loading,
        iconPos = 'left',
        icon,
        disabled,
        outlined,
        raised,
        rounded,
        testID,
        style: styleProp,
        onPress,
        onClick,
        ...rest
    } = props;

    const {t} = useLanguage();
    const {cssProps, nativeProps} = useSeparator<Record<any, any>>(rest);
    const sevColors = useSeverityColors((severity as any) ?? 'brand');

    const sizeConfig = SIZE_MAP[size as keyof typeof SIZE_MAP] ?? SIZE_MAP.md;
    const isDisabled = disabled || loading;

    /* ── Resolve label text ── */
    const resolvedLabel = typeof children === 'string'
        ? children
        : loading && isLoadingText
            ? isLoadingText
            : label ? t(label) : '';

    const hasLabel = !!resolvedLabel;

    /* ── Severity colors ── */
    const textColor = outlined ? sevColors.solid : sevColors.solidText;
    const bgColor = outlined ? 'transparent' : sevColors.solid;
    const borderColor = sevColors.border || sevColors.solid;

    /* ── Build CSS props for ResponsiveElement ── */
    const computedCss = useMemo(() => ({
        ...themeStyle,
        ...(elementStyles.root || {}),
        ...cssProps,
        backgroundColor: bgColor,
        borderColor,
        borderWidth: 1,
        height: sizeConfig.height,
        paddingLeft: hasLabel ? sizeConfig.px : sizeConfig.py,
        paddingRight: hasLabel ? sizeConfig.px : sizeConfig.py,
        paddingTop: sizeConfig.py,
        paddingBottom: sizeConfig.py,
        borderRadius: rounded ? 9999 : 6,
        flexDirection: iconPos === 'top' || iconPos === 'bottom'
            ? (iconPos === 'bottom' ? 'column-reverse' : 'column')
            : (iconPos === 'right' ? 'row-reverse' : 'row'),
        alignItems: 'center',
        justifyContent: 'center',
        gap: sizeConfig.gap,
        opacity: isDisabled ? 50 : 100,
        alignSelf: 'flex-start',
        overflow: 'hidden',
        ...(raised ? {
            shadowColor: '#000',
            shadowOffset: {width: 0, height: 3},
            shadowOpacity: 0.16,
            shadowRadius: 6,
            elevation: 4,
        } : {}),
        ...styleProp,
    }), [themeStyle, elementStyles, cssProps, bgColor, borderColor, sizeConfig,
        hasLabel, icon, iconPos, rounded, raised, isDisabled, styleProp]);

    /* ── Icon element ── */
    const iconElement = loading
        ? <ActivityIndicator size="small" color={textColor} />
        : resolveIcon(icon, textColor, sizeConfig.iconSize);

    /* ── Text style ── */
    const labelStyle: TextStyle = useMemo(() => ({
        color: textColor,
        fontSize: sizeConfig.fontSize,
        fontWeight: '600',
        lineHeight: sizeConfig.fontSize * 1.2,
    }), [textColor, sizeConfig]);

    /* ── Press handler ── */
    const handlePress = useCallback((e: GestureResponderEvent) => {
        if (isDisabled) return;
        if (onPress) onPress(e as any);
        if (onClick) onClick(e as any);
    }, [isDisabled, onPress, onClick]);

    return (
        <ResponsiveElement
            as="Pressable"
            cssProps={computedCss}
            nativeProps={{
                ...nativeProps,
                onPress: handlePress,
                disabled: isDisabled,
                testID,
                accessibilityRole: 'button',
                accessibilityState: {disabled: isDisabled, busy: loading},
                accessibilityLabel: resolvedLabel || undefined,
            }}
        >
            {iconElement}
            {!!hasLabel && (
                <RNText style={labelStyle} numberOfLines={1}>
                    {resolvedLabel}
                </RNText>
            )}
            {typeof children !== 'string' ? children : undefined}
        </ResponsiveElement>
    );
}

export default Button;
